const sqlite3 = require('sqlite3'); const db = new sqlite3.Database('./db.sqlite'); db.run('CREATE TABLE login_attempt (id INTEGER PRIMARY KEY AUTOINCREMENT, ipAddress TEXT NOT NULL, userAgent TEXT NOT NULL, email TEXT, status TEXT NOT NULL DEFAULT \
failed\, metadata TEXT, failureReason TEXT, createdAt datetime NOT NULL DEFAULT datetime(\now\), userId varchar, FOREIGN KEY (userId) REFERENCES users(id) ON DELETE SET NULL)', (err) => { if (err) { console.error('Error creating table:', err); } else { console.log('New table created with correct foreign key reference'); } db.close(); });
